module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

reg [15:0] a_reg;
reg [7:0] b_reg;

always @* begin
    a_reg = A;
    b_reg = B;

    if (b_reg != 0) begin
        result = a_reg / b_reg;
        odd = a_reg % b_reg;
    end else begin
        result = 0;
        odd = a_reg;
    end
end
endmodule
